```typescript
import { NextResponse } from "next/server";
import { z } from "zod";
import { prisma } from "@rlm-saas/database";

// Define the schema for query parameters using Zod
const querySchema = z.object({
  page: z.number().optional().default(1),
  limit: z.number().optional().default(10),
});

export async function GET(request: Request) {
  // Parse and validate query parameters
  const { searchParams } = new URL(request.url);
  const parsedQuery = querySchema.safeParse(Object.fromEntries(searchParams));

  if (!parsedQuery.success) {
    return NextResponse.json(
      { error: "Invalid query parameters", issues: parsedQuery.error.errors },
      { status: 400 }
    );
  }

  const { page, limit } = parsedQuery.data;

  // Fetch users from Prisma with pagination
  const users = await prisma.user.findMany({
    skip: (page - 1) * limit,
    take: limit,
  });

  return NextResponse.json(users);
}
```

### Explanation:
1. **Zod Schema**: The `querySchema` defines the expected query parameters (`page` and `limit`) with default values.
2. **GET Handler**: The `GET` function handles incoming requests. It parses the query parameters from the request URL and validates them against the Zod schema.
3. **Error Handling**: If validation fails, it returns a 400 status with error details.
4. **Prisma Query**: It fetches users from the database using pagination based on the validated `page` and `limit` values.
5. **Response**: Finally, it returns the list of users as a JSON response.

